from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, Float
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship

Base = declarative_base()

class Bicycle(Base):
    __tablename__ = 'bicycles'

    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    price = Column(Float, nullable=False)
    type = Column(String, nullable=False)  # e.g., mountain, road, hybrid
    parts = relationship('Part', back_populates='bicycle')

class Part(Base):
    __tablename__ = 'parts'

    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    price = Column(Float, nullable=False)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))
    bicycle = relationship('Bicycle', back_populates='parts')

class Accessory(Base):
    __tablename__ = 'accessories'

    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    price = Column(Float, nullable=False)

def create_database(db_url):
    engine = create_engine(db_url)
    Base.metadata.create_all(engine)
    return engine

def get_session(engine):
    Session = sessionmaker(bind=engine)
    return Session()

def add_bicycle(session, name, price, type):
    new_bicycle = Bicycle(name=name, price=price, type=type)
    session.add(new_bicycle)
    session.commit()

def delete_bicycle(session, bicycle_id):
    bicycle = session.query(Bicycle).filter(Bicycle.id == bicycle_id).first()
    if bicycle:
        session.delete(bicycle)
        session.commit()

def update_bicycle(session, bicycle_id, name=None, price=None, type=None):
    bicycle = session.query(Bicycle).filter(Bicycle.id == bicycle_id).first()
    if bicycle:
        if name:
            bicycle.name = name
        if price:
            bicycle.price = price
        if type:
            bicycle.type = type
        session.commit()

def get_bicycles(session):
    return session.query(Bicycle).all()

def search_bicycles(session, search_term):
    return session.query(Bicycle).filter(Bicycle.name.ilike(f'%{search_term}%')).all()

def add_part(session, name, price, bicycle_id):
    new_part = Part(name=name, price=price, bicycle_id=bicycle_id)
    session.add(new_part)
    session.commit()

def delete_part(session, part_id):
    part = session.query(Part).filter(Part.id == part_id).first()
    if part:
        session.delete(part)
        session.commit()

def update_part(session, part_id, name=None, price=None):
    part = session.query(Part).filter(Part.id == part_id).first()
    if part:
        if name:
            part.name = name
        if price:
            part.price = price
        session.commit()

def get_parts(session):
    return session.query(Part).all()

def add_accessory(session, name, price):
    new_accessory = Accessory(name=name, price=price)
    session.add(new_accessory)
    session.commit()

def delete_accessory(session, accessory_id):
    accessory = session.query(Accessory).filter(Accessory.id == accessory_id).first()
    if accessory:
        session.delete(accessory)
        session.commit()

def update_accessory(session, accessory_id, name=None, price=None):
    accessory = session.query(Accessory).filter(Accessory.id == accessory_id).first()
    if accessory:
        if name:
            accessory.name = name
        if price:
            accessory.price = price
        session.commit()

def get_accessories(session):
    return session.query(Accessory).all()

